    goal: sentiment_label
    constraints {
        output in ["positive", "negative", "mixed", "unclear"]
    }
}

intent respond_warmly(text: Text) -> Text {
    goal: Text warm supportive reply
}

intent respond_carefully(text: Text) -> Text {
    goal: Text careful empathetic reply
}

intent ask_clarifying_question(text: Text) -> Text {
    goal: Text clarifying question
}

entry main(message: Text) {
    sentiment = classify_sentiment(message)
    branch sentiment {
        [sentiment == "positive"]    => reply = respond_warmly(message)
        [sentiment == "negative"]    => reply = respond_carefully(message)
        [sentiment == "mixed"]       => reply = ask_clarifying_question(message)
        [otherwise]                  => reply = ask_clarifying_question(message)
    }
    return reply
}

