//
// Uses the bundled standard library instead of redefining primitives.
// Shows how a short AIL program composes two stdlib intents with
// context-driven behavior.
//
// Flow: take a long piece of text, summarize it, then classify the
// summary's sentiment. Both summarize and classify come from
// stdlib/language — the user's program only adds the composition
// and the context that shapes how they run.

import summarize from "stdlib/language"
import classify from "stdlib/language"

context editorial_review extends default {
    register: "neutral"
    audience: "general_reader"
    preserve: [names, dates, numbers]
}

entry main(article: Text) {
    with context editorial_review:
        brief = summarize(article, 80)
        mood = classify(brief, "positive_negative_mixed_unclear")
    return mood
}

pure fn is_prime(n: Number) -> Boolean {
    if n < 2 { return false }
    for d in range(2, n) {
        if d * d > n { return true }
        if n % d == 0 { return false }
    }
    return true
}
entry main(x: Text) {
    if is_prime(29) { return "yes" }
    return "no"
}

pure fn square(n: Number) -> Number { return n * n }
pure fn sum_of_squares(lo: Number, hi: Number) -> Number {
    total = 0
    for i in range(lo, hi + 1) { total = total + square(i) }
    return total
}
entry main(x: Text) { return sum_of_squares(1, 5) }

pure fn direct_parse(text: Text) -> Number {
    return to_number(trim(text))
}
pure fn scan_tokens(text: Text) -> Number {
    for t in split(text, " ") {
        parsed = to_number(t)
        if is_ok(parsed) { return parsed }
    }
    return error("no numeric token found")
}
intent infer_number(text: Text) -> Text {
    goal: the single number in the text or the word unknown
}
entry main(text: Text) {
    return attempt {
        try direct_parse(text)
        try scan_tokens(text)
        try infer_number(text)
    }
}

pure fn max_of(nums: Number) -> Number {
    best = get(nums, 0)
    for n in nums {
        if n > best { best = n }
    }
    return best
}
